const q = ($json.chatInput || "").toLowerCase();

if (q.includes("close")) {
  return { reply_type: "close", assistant_reply: "Goodbye 👋 Thanks for visiting GKWebTech!" };
}

if (q.includes("restart") || q === "menu" || q === "hi" || q === "hello") {
  return {
    reply_type: "menu",
    assistant_reply: "Hi 👋 I’m Ayuu. What would you like to explore?",
    menu: [
      { title: "Agency Services", value: "services", link: "/#services" },
      { title: "Institute/Training", value: "institute", link: "/#institute" },
      { title: "Portfolio", value: "portfolio", link: "/#portfolio" },
      { title: "Contact Us", value: "contact", link: "/#contact" }
    ]
  };
}

if (q.includes("services")) {
  return {
    reply_type: "menu",
    assistant_reply: "Here are our Agency Services. You can also visit: /#services",
    menu: [
      { title: "Web Development", value: "Tell me about Web Development", link: "/#web-dev" },
      { title: "SEO", value: "Tell me about SEO", link: "/#seo" },
      { title: "Social Media Management", value: "Tell me about SMM", link: "/#social-media" },
      { title: "Performance Ads", value: "Tell me about Meta/Google Ads", link: "/#ads" },
      { title: "Automation Solutions", value: "Tell me about Automation", link: "/#automation" },
      { title: "Back to Main Menu", value: "menu" }
    ]
  };
}

if (q.includes("portfolio")) {
  return {
    reply_type: "menu",
    assistant_reply: "Check our work here: /#portfolio",
    menu: [
      { title: "Agency Projects", link: "/#portfolio-agency" },
      { title: "Institute Batches", link: "/#portfolio-institute" },
      { title: "Case Studies", link: "/#case-studies" },
      { title: "Back to Menu", value: "menu" }
    ]
  };
}

if (q.includes("contact")) {
  return {
    reply_type: "contact",
    assistant_reply: "You can reach us via:",
    contact_options: [
      { title: "Email Us", action: "mailto", value: "gkwebtech@gmail.com" },
      { title: "Call Us", action: "tel", value: "+919876543210" },
      { title: "Office Location", action: "maps", query: "Delhi,India" }
    ]
  };
}

return { assistant_reply: null, reply_type: "menu" };

const r = $input.first().json;

let reply = r.output || r.assistant_reply || null;

// If Gemini says it doesn't know, restart menu
if (reply && reply.toLowerCase().includes("menu")) {
  return {
    reply_type: "menu",
    assistant_reply: "I can help you explore 👇 What would you like?",
    menu: [
      { title: "Agency Services", value: "services", link: "/#services" },
      { title: "Institute/Training", value: "institute", link: "/#institute" },
      { title: "Portfolio", value: "portfolio", link: "/#portfolio" },
      { title: "Contact Us", value: "contact", link: "/#contact" }
    ]
  };
}

return {
  assistant_reply: reply,
  reply_type: "generated",
  menu: null
};
